namespace test_reaction {

// ============================================
// 函数实现
// ============================================

/**
 * Function: Test batch operations on observer nodes
 *
 * @return bool Whether batch operations work correctly
 */
bool test_batch_operations() {
    using namespace reaction;

    // 1. Create observer nodes
    auto node1 = std::make_shared<ObserverNode>();
    auto node2 = std::make_shared<ObserverNode>();
    auto node3 = std::make_shared<ObserverNode>();

    // 2. Get observer graph instance
    auto& graph = ObserverGraph::getInstance();

    // Add nodes to graph
    graph.addNode(node1);
    graph.addNode(node2);
    graph.addNode(node3);

    // 3. Create batch ID
    BatchId batch_id = BatchRegistry::createBatch();

    // 4. Register nodes to batch
    BatchRegistry::registerNode(batch_id, node1);
    BatchRegistry::registerNode(batch_id, node2);
    BatchRegistry::registerNode(batch_id, node3);

    // 5. Verify nodes are in batch
    if (!BatchRegistry::isInBatch(node1) || 
        !BatchRegistry::isInBatch(node2) || 
        !BatchRegistry::isInBatch(node3)) {
        return false;
    }

    // Check if they're all in the same batch
    if (BatchRegistry::getBatchId(node1).value_or(BatchId{0}) != batch_id ||
        BatchRegistry::getBatchId(node2).value_or(BatchId{0}) != batch_id ||
        BatchRegistry::getBatchId(node3).value_or(BatchId{0}) != batch_id) {
        return false;
    }

    // 6. Unregister batch
    BatchRegistry::unregisterBatch(batch_id);

    // 7. Verify nodes are no longer in batch
    if (BatchRegistry::isInBatch(node1) || 
        BatchRegistry::isInBatch(node2) || 
        BatchRegistry::isInBatch(node3)) {
        return false;
    }

    // Also verify their batch IDs are no longer set
    if (BatchRegistry::getBatchId(node1).has_value() ||
        BatchRegistry::getBatchId(node2).has_value() ||
        BatchRegistry::getBatchId(node3).has_value()) {
        return false;
    }

    // 8. Return success status
    return true;
}

}  // namespace test_reaction
