    nodeB->reset();
    nodeC->reset();

    // 6. Attempt transactional update that would create cycle: C -> A
    bool cycleCaught = false;
    try {
        graph.addObserver(nodeC, nodeA);  // This should create a cycle A -> B -> C -> A
    } catch (const std::runtime_error& e) {
        // 7. Catch cycle exception if thrown
        cycleCaught = true;
    }

    if (!cycleCaught) {
