    auto target = std::make_shared<reaction::ObserverNode>();
    auto observer1 = std::make_shared<TestChainedObserver>(observer1Name);
    auto observer2 = std::make_shared<TestChainedObserver>(observer2Name);

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up chain relationships: target -> observer1 -> observer2
    graph.addObserver(target, observer1);
    graph.addObserver(observer1, observer2);

    // Reset call counts before testing
    observer1->reset();
    observer2->reset();

    // 4. Notify target
    target->valueChanged(true);

    // 5. Verify both observers were notified
    bool chainWorked = observer1->wasChanged() && observer2->wasChanged();

    // 6. Calculate total call count
    int totalCallCount = observer1->getCallCount() + observer2->getCallCount();

    // 7. Return total call count and chain status
    return std::make_pair(totalCallCount, chainWorked);
}

