namespace test_reaction {

struct ResourceAtomicResult {
    int finalValue;
    bool operationReportedChange;
};

inline ResourceAtomicResult test_resource_atomic(int initialValue, int delta) {
    // 1. Create a Resource instance
    reaction::Resource<int> resource(initialValue);

    // 2. Create a variable to track whether operation reported a change
    bool changed = false;

    // 3. Perform an atomic operation that adds delta to the value
    resource.atomic([&](int& value) {
        value += delta;
        changed = true;  // In this lambda we assume change happens
    });

    // 4. Get the final value
    int finalValue = resource.get();

    // 5. Return resource atomic result
    return {finalValue, changed};
}

}  // namespace test_reaction
