    // 5. Apply atomic multiply assignment
    reaction::atomicMultiplyAssign(atom, 2);
    // 6. Check if multiply operation reported change
    bool multiplyReportedChange = atom.lastReportedChange();

    // 7. Apply atomic bitwise AND assignment
    reaction::atomicBitwiseAndAssign(atom, 0xF);
    // 8. Check if bitwise AND operation reported change
    bool andReportedChange = atom.lastReportedChange();

    // 9. Apply atomic left shift assignment
    reaction::atomicLeftShiftAssign(atom, 2);
    // 10. Check if left shift operation reported change
    bool leftShiftReportedChange = atom.lastReportedChange();

    // 11. Apply atomic increment
    reaction::atomicIncrement(atom);
    // 12. Check if increment operation reported change
    bool incrementReportedChange = atom.lastReportedChange();

    // 13. Get final value
    int32_t finalValue = atom.value();

    // 14. Return atomic helper snapshot
    return {
        finalValue,
        addReportedChange,
        multiplyReportedChange,
        andReportedChange,
        leftShiftReportedChange,
        incrementReportedChange
    };
}

